from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get the raw request body as a string
        data = request.get_data(as_text=True)
        if not data:
            return jsonify({"error": "No data provided"}), 400

        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # yaml.load() is unsafe for untrusted input.
        parsed_data = yaml.safe_load(data)

        # Ensure the result is a type that can be serialized to JSON
        if parsed_data is None:
            return jsonify({"message": "YAML is empty"}), 200

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": "An internal server error occurred"}), 500
